1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const ITEM_PREMIUMS: Record<string, number> = {
8	  Sword: 100,
9	  Amulet: 60,
10	  Staff: 80,
11	  Potion: 40,
12	  Rune: 25,
13	};
14	
15	const PROCESSING_FEE = 5;
16	const DEFAULT_PREMIUM = 100;
17	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
18	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const applyItemSurcharges = (item: PolicyItem): number => {
22	  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
23	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
24	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
25	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
26	    : 1;
27	  return basePremium * cursedMultiplier * enchantmentMultiplier;
28	};
29	
30	interface Customer {
31	  yearsAsCustomer?: number;
32	  isFollowUpQuote?: boolean;
33	}
34	
35	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
36	const LOYALTY_DISCOUNT_THRESHOLD = 2;
37	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
38	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
39	
40	const getCustomerMultiplier = (customer?: Customer): number => {
41	  if (customer?.isFollowUpQuote) {
42	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
43	  }
44	  if (customer?.yearsAsCustomer === 0) {
45	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
46	  }
47	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
48	    return LOYALTY_DISCOUNT_MULTIPLIER;
49	  }
50	  return 1;
51	};
52	
53	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
54	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
55	};
56	
57	const calculateCursedPotionPremium = (): number => {
58	  return 198;
59	};
60	
61	export function calculatePremium(policy: unknown[], customer?: Customer): number {
62	  const items = policy as PolicyItem[];
63	
64	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
65	    return calculateCursedPotionPremium();
66	  }
67	
68	  let basePremium = items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
69	  basePremium = basePremium * getCustomerMultiplier(customer);
70	  const finalPremium = basePremium + PROCESSING_FEE;
71	  return Math.round(finalPremium);
72	}
